-- Name: navigation_items Allow authenticated users to read active navigation items; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Allow authenticated users to read active navigation items" ON public.navigation_items FOR SELECT TO authenticated USING (((is_active = true) OR (EXISTS ( SELECT 1
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'platform_admin'::text))))));


