--
-- Name: checklist_progress checklist_progress_read; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY checklist_progress_read ON public.checklist_progress FOR SELECT TO authenticated USING (((EXISTS ( SELECT 1
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'platform_admin'::text)))) OR (sub_account_id IN ( SELECT sub_accounts.id
   FROM public.sub_accounts
  WHERE (sub_accounts.agency_id IN ( SELECT user_roles.agency_id
           FROM public.user_roles
          WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'agency_admin'::text)))))) OR (sub_account_id IN ( SELECT user_roles.sub_account_id
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'sub_account_user'::text))))));


--
-- Name: checklist_progress checklist_progress_write; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY checklist_progress_write ON public.checklist_progress TO authenticated USING (((EXISTS ( SELECT 1
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'platform_admin'::text)))) OR (sub_account_id IN ( SELECT sub_accounts.id
   FROM public.sub_accounts
  WHERE (sub_accounts.agency_id IN ( SELECT user_roles.agency_id
           FROM public.user_roles
          WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'agency_admin'::text)))))) OR (sub_account_id IN ( SELECT user_roles.sub_account_id
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'sub_account_user'::text)))))) WITH CHECK (((EXISTS ( SELECT 1
   FROM public.user_roles
  WHERE ((user_roles.user_id = auth.uid()) AND (user_roles.role = 'platform_admin'::text)))) OR (sub_account_id IN ( SELECT sub_accounts.id
   FROM public.sub_accounts
